import{_ as e,o as t,c as l,ag as i}from"./chunks/framework.CTpQozEL.js";const u=JSON.parse('{"title":"BTW 사이드 질문","description":"/btw로 임시 사이드 질문 처리","frontmatter":{"title":"BTW 사이드 질문","description":"/btw로 임시 사이드 질문 처리"},"headers":[],"relativePath":"tools/btw.md","filePath":"tools/btw.md","lastUpdated":null}'),o={name:"tools/btw.md"};function s(n,a,r,c,d,p){return t(),l("div",null,[...a[0]||(a[0]=[i(`<h1 id="btw-사이드-질문" tabindex="-1">BTW 사이드 질문 <a class="header-anchor" href="#btw-사이드-질문" aria-label="Permalink to &quot;BTW 사이드 질문&quot;">​</a></h1><p><code>/btw</code>는 해당 질문을 일반 대화 히스토리로 전환하지 않고 <strong>현재 세션</strong>에 대해 빠른 사이드 질문을 할 수 있게 해줍니다.</p><p>Claude Code의 <code>/btw</code> 동작을 모델로 삼았지만, OpenClaw의 게이트웨이 및 멀티 채널 아키텍처에 맞게 조정되었습니다.</p><h2 id="동작-방식" tabindex="-1">동작 방식 <a class="header-anchor" href="#동작-방식" aria-label="Permalink to &quot;동작 방식&quot;">​</a></h2><p>다음을 전송하면:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/btw what changed?</span></span></code></pre></div><p>OpenClaw는 다음을 수행합니다:</p><ol><li>현재 세션 컨텍스트를 스냅샷합니다,</li><li>별도의 <strong>도구 없는</strong> 모델 호출을 실행합니다,</li><li>사이드 질문에만 답변합니다,</li><li>메인 실행을 그대로 유지합니다,</li><li>BTW 질문이나 답변을 세션 히스토리에 <strong>기록하지 않습니다</strong>,</li><li>일반 어시스턴트 메시지 대신 <strong>라이브 사이드 결과</strong>로 답변을 제공합니다.</li></ol><p>중요한 개념 모델:</p><ul><li>동일한 세션 컨텍스트</li><li>별도의 원샷 사이드 쿼리</li><li>도구 호출 없음</li><li>향후 컨텍스트 오염 없음</li><li>기록 지속성 없음</li></ul><h2 id="하지-않는-것" tabindex="-1">하지 않는 것 <a class="header-anchor" href="#하지-않는-것" aria-label="Permalink to &quot;하지 않는 것&quot;">​</a></h2><p><code>/btw</code>는 다음을 <strong>하지 않습니다</strong>:</p><ul><li>새로운 영구 세션 생성,</li><li>미완료된 메인 태스크 계속,</li><li>도구 또는 에이전트 도구 루프 실행,</li><li>BTW 질문/답변 데이터를 기록 히스토리에 저장,</li><li><code>chat.history</code>에 나타나기,</li><li>재로드 후 유지.</li></ul><p>의도적으로 <strong>일시적</strong>으로 설계되었습니다.</p><h2 id="컨텍스트-작동-방식" tabindex="-1">컨텍스트 작동 방식 <a class="header-anchor" href="#컨텍스트-작동-방식" aria-label="Permalink to &quot;컨텍스트 작동 방식&quot;">​</a></h2><p>BTW는 현재 세션을 <strong>배경 컨텍스트로만</strong> 사용합니다.</p><p>메인 실행이 현재 활성 상태인 경우, OpenClaw는 현재 메시지 상태를 스냅샷하고 진행 중인 메인 프롬프트를 배경 컨텍스트로 포함하면서 모델에게 명시적으로 알립니다:</p><ul><li>사이드 질문에만 답변하고,</li><li>미완료된 메인 태스크를 재개하거나 완료하지 말고,</li><li>도구 호출이나 유사 도구 호출을 내보내지 마십시오.</li></ul><p>이를 통해 BTW는 메인 실행과 격리되면서도 세션의 내용을 인식할 수 있습니다.</p><h2 id="전달-모델" tabindex="-1">전달 모델 <a class="header-anchor" href="#전달-모델" aria-label="Permalink to &quot;전달 모델&quot;">​</a></h2><p>BTW는 일반 어시스턴트 기록 메시지로 전달되지 <strong>않습니다</strong>.</p><p>게이트웨이 프로토콜 수준에서:</p><ul><li>일반 어시스턴트 채팅은 <code>chat</code> 이벤트를 사용합니다</li><li>BTW는 <code>chat.side_result</code> 이벤트를 사용합니다</li></ul><p>이 분리는 의도적입니다. BTW가 일반 <code>chat</code> 이벤트 경로를 재사용하면, 클라이언트는 이를 일반 대화 히스토리로 취급할 것입니다.</p><p>BTW는 별도의 라이브 이벤트를 사용하고 <code>chat.history</code>에서 재생되지 않으므로, 재로드 후 사라집니다.</p><h2 id="표면-동작" tabindex="-1">표면 동작 <a class="header-anchor" href="#표면-동작" aria-label="Permalink to &quot;표면 동작&quot;">​</a></h2><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to &quot;TUI&quot;">​</a></h3><p>TUI에서 BTW는 현재 세션 뷰에 인라인으로 렌더링되지만, 일시적으로 유지됩니다:</p><ul><li>일반 어시스턴트 답변과 시각적으로 구분됩니다</li><li><code>Enter</code> 또는 <code>Esc</code>로 해제 가능합니다</li><li>재로드 시 재생되지 않습니다</li></ul><h3 id="외부-채널" tabindex="-1">외부 채널 <a class="header-anchor" href="#외부-채널" aria-label="Permalink to &quot;외부 채널&quot;">​</a></h3><p>Telegram, WhatsApp, Discord 같은 채널에서 BTW는 해당 표면에 로컬 임시 오버레이 개념이 없기 때문에 명확하게 레이블이 붙은 1회성 답변으로 전달됩니다.</p><p>답변은 여전히 사이드 결과로 처리되며, 일반 세션 히스토리로 처리되지 않습니다.</p><h3 id="control-ui-웹" tabindex="-1">Control UI / 웹 <a class="header-anchor" href="#control-ui-웹" aria-label="Permalink to &quot;Control UI / 웹&quot;">​</a></h3><p>게이트웨이는 BTW를 <code>chat.side_result</code>로 올바르게 내보내고, BTW는 <code>chat.history</code>에 포함되지 않으므로, 웹에 대한 지속성 계약은 이미 올바릅니다.</p><p>현재 Control UI에는 BTW를 브라우저에서 라이브로 렌더링하기 위한 전용 <code>chat.side_result</code> 소비자가 아직 필요합니다. 클라이언트 측 지원이 도착할 때까지, BTW는 완전한 TUI 및 외부 채널 동작을 갖춘 게이트웨이 수준 기능이지만, 아직 완전한 브라우저 UX는 아닙니다.</p><h2 id="사용-시기" tabindex="-1">사용 시기 <a class="header-anchor" href="#사용-시기" aria-label="Permalink to &quot;사용 시기&quot;">​</a></h2><p>다음을 원할 때 <code>/btw</code>를 사용합니다:</p><ul><li>현재 작업에 대한 빠른 설명,</li><li>긴 실행이 진행 중인 동안의 사실적인 사이드 답변,</li><li>향후 세션 컨텍스트의 일부가 되어서는 안 되는 임시 답변.</li></ul><p>예시:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/btw what file are we editing?</span></span>
<span class="line"><span>/btw what does this error mean?</span></span>
<span class="line"><span>/btw summarize the current task in one sentence</span></span>
<span class="line"><span>/btw what is 17 * 19?</span></span></code></pre></div><h2 id="사용하지-않을-시기" tabindex="-1">사용하지 않을 시기 <a class="header-anchor" href="#사용하지-않을-시기" aria-label="Permalink to &quot;사용하지 않을 시기&quot;">​</a></h2><p>답변이 세션의 향후 작업 컨텍스트의 일부가 되기를 원한다면 <code>/btw</code>를 사용하지 마십시오.</p><p>그 경우, BTW 대신 메인 세션에서 일반적으로 질문하십시오.</p><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/tools/slash-commands">슬래시 커맨드</a></li><li><a href="/openclaw-docs-ko/tools/thinking">사고 수준</a></li><li><a href="/openclaw-docs-ko/concepts/session">세션</a></li></ul>`,45)])])}const b=e(o,[["render",s]]);export{u as __pageData,b as default};
